fn append_is_new(
    idempotency_key_present: bool,
    existing_key_matches: bool,
    existing_key_conflicts: bool,
) -> bool {
    (idempotency_key_present == false)
        || ((existing_key_matches == false) && (existing_key_conflicts == false))
}

